// Valida e normaliza cada item recebido do ERP
const validated = [];
const errors = [];

for (const item of items) {
  const sku   = String(item.json.sku || '').trim();
  const client = String(item.json.client || 'N/A').trim();
  const sales = Number(item.json.sales);
  const stock = Number(item.json.stock);
  const cost  = Number(item.json.cost);

  if (!sku) { errors.push({ reason: 'SKU vazio', raw: item.json }); continue; }
  if (isNaN(sales) || isNaN(stock) || isNaN(cost)) { errors.push({ reason: 'Campo numérico inválido', raw: item.json }); continue; }
  if (cost <= 0 || stock < 0) { errors.push({ reason: 'Custo inválido ou valor negativo', raw: item.json }); continue; }

  validated.push({ json: { sku, client, sales, stock, cost } });
}

if (errors.length > 0) {
  console.error('[DataCleaning] Itens descartados:', JSON.stringify(errors));
}

return validated;

// Agrupa todos os itens em um único array para enviar ao backend
const allData = items.map(i => i.json);
return [{ json: { data: allData } }];

