// Consolida forecast + inventory + pricing num único objeto por SKU
// Recebe os 3 inputs (um item de cada endpoint da API)
const allInputs = $input.all();
const forecast  = (allInputs[0]?.json?.results || []);
const inventory = (allInputs[1]?.json?.results || []);
const pricing   = (allInputs[2]?.json?.results || []);

const bySkuF = Object.fromEntries(forecast.map(r  => [r.sku, r]));
const bySkuI = Object.fromEntries(inventory.map(r => [r.sku, r]));
const bySkuP = Object.fromEntries(pricing.map(r   => [r.sku, r]));

const allSkus = [...new Set([...Object.keys(bySkuF), ...Object.keys(bySkuI), ...Object.keys(bySkuP)])];

const consolidated = allSkus.map(sku => ({
  sku,
  client:          bySkuF[sku]?.client || bySkuI[sku]?.client || '',
  forecast_30d:    bySkuF[sku]?.forecast_30d || 0,
  days_of_stock:   bySkuF[sku]?.days_of_stock || 0,
  risk:            bySkuF[sku]?.risk || 'N/A',
  inventory_status: bySkuI[sku]?.inventory_status || 'N/A',
  suggested_order:  bySkuI[sku]?.suggested_order || 0,
  stock_value_brl:  bySkuI[sku]?.stock_value_brl || 0,
  excess_alert:    bySkuI[sku]?.excess_alert || false,
  suggested_price: bySkuP[sku]?.suggested_price || 0,
  margin_pct:      bySkuP[sku]?.margin_pct || 0,
  pricing_action:  bySkuP[sku]?.pricing_action || 'N/A',
  processed_at:    new Date().toISOString(),
}));

return consolidated.map(r => ({ json: r }));

