// Compila o resumo diário
const total     = items.length;
const criticos  = items.filter(i => i.json.risk === 'CRÍTICO').length;
const excessos  = items.filter(i => i.json.excess_alert).length;
const reposicao = items.filter(i => i.json.inventory_status === 'REPOSIÇÃO').length;
const valorTotal = items.reduce((s, i) => s + (i.json.stock_value_brl || 0), 0).toFixed(2);

return [{ json: {
  report_date: new Date().toLocaleDateString('pt-BR'),
  total_skus:  total,
  criticos,
  excessos,
  reposicao,
  valor_imobilizado_brl: valorTotal,
  summary_text: `📊 *Relatório Supply Chain ${new Date().toLocaleDateString('pt-BR')}*\n• Total SKUs processados: ${total}\n• Estoque crítico: ${criticos}\n• Estoque excessivo: ${excessos}\n• Em reposição: ${reposicao}\n• Valor imobilizado total: R$ ${Number(valorTotal).toLocaleString('pt-BR')}`,
}}];

const err = items[0].json;
const nodeName = err.node || err.workflow?.last_node || 'desconhecido';
const message  = err.message || err.description || 'Erro sem mensagem';
return [{ json: {
  error_node: nodeName,
  error_message: message,
  timestamp: new Date().toISOString(),
  alert: `🔴 *Erro no workflow Supply Chain*\nNó: ${nodeName}\nDetalhe: ${message}`,
}}];

// Verifica se forecast total atinge a meta mensal da Santista
// Meta: 65-70M metros/ano → ~5.8M metros/mês (reunião 10/04/2026)
const META_MENSAL = 5800000;
const totalForecast = items.reduce((s, i) => s + (i.json.forecast_30d || 0), 0);
const pct = ((totalForecast / META_MENSAL) * 100).toFixed(1);
const onTrack = totalForecast >= META_MENSAL;
const status = onTrack ? '✅ ON TRACK' : '⚠️ ABAIXO DA META';
const emoji = onTrack ? '📈' : '📉';
return [{ json: {
  totalForecast: Math.round(totalForecast),
  meta_mensal: META_MENSAL,
  pct_meta: pct,
  on_track: onTrack,
  volume_status: status,
  volume_alert: `${emoji} *Volume forecast 30d:* ${Math.round(totalForecast).toLocaleString()} metros\n• Meta mensal: ${META_MENSAL.toLocaleString()} metros\n• Atingimento: *${pct}%* | ${status}`,
}}];
